import React, { useState, useRef, useEffect } from 'react';

// ============================================================
//  🔮 KAL KA ANKUR — Chat with Your Future Self
//  User fills a short profile → AI responds AS their future self
//  5 years ahead, same struggles, but wiser and survived them
// ============================================================

const FUTURE_YEARS = 5;

const SETUP_QUESTIONS = [
  {
    id: 'name',
    question: 'Tumhara naam kya hai?',
    placeholder: 'Apna naam likho...',
    type: 'text',
  },
  {
    id: 'struggle',
    question: 'Aaj sabse badi mushkil kya hai tumhari zindagi mein?',
    placeholder: 'Exams, family pressure, career confusion, kuch bhi...',
    type: 'textarea',
  },
  {
    id: 'dream',
    question: 'Ek sapna jo tumhara hai — chahe kitna bhi bada ho?',
    placeholder: 'Jo tumhare dil mein hai woh likho...',
    type: 'textarea',
  },
  {
    id: 'fear',
    question: 'Sabse bada dar kya hai? Jo raat ko sone nahi deta?',
    placeholder: 'Koi judge nahi karega — sach likho...',
    type: 'textarea',
  },
];

// ── Main Component ─────────────────────────────────────────
const KalKaAnkur = ({ onClose }) => {
  const [phase, setPhase] = useState('intro'); // intro | setup | chat | 
  const [setupStep, setSetupStep] = useState(0);
  const [profile, setProfile] = useState({ name: '', struggle: '', dream: '', fear: '' });
  const [currentInput, setCurrentInput] = useState('');
  const [messages, setMessages] = useState([]);
  const [isLoading, setIsLoading] = useState(false);
  const [setupAnswers, setSetupAnswers] = useState({});
  const messagesEndRef = useRef(null);
  const currentYear = new Date().getFullYear();
  const futureYear = currentYear + FUTURE_YEARS;

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading]);

  const handleSetupNext = () => {
    const q = SETUP_QUESTIONS[setupStep];
    if (!currentInput.trim()) return;
    const updated = { ...setupAnswers, [q.id]: currentInput.trim() };
    setSetupAnswers(updated);
    setCurrentInput('');
    if (setupStep < SETUP_QUESTIONS.length - 1) {
      setSetupStep(prev => prev + 1);
    } else {
      setProfile(updated);
      startFutureChat(updated);
    }
  };

  const startFutureChat = async (p) => {
    setPhase('chat');
    setIsLoading(true);

    const openingPrompt = `You are ${p.name}'s future self, ${FUTURE_YEARS} years from now (year ${futureYear}). 

Current struggles they shared: "${p.struggle}"
Their dream: "${p.dream}"  
Their biggest fear: "${p.fear}"

Write your FIRST message as their future self. You:
- Survived all of this and came out stronger
- Remember exactly how hard ${currentYear} was
- Speak in warm Hinglish, like talking to yourself
- Start with something only THEY would know about their current pain
- Don't reveal too much — be mysterious but deeply comforting
- 100-120 words max
- End with one question to start the conversation`;

    try {
      const res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          model: 'claude-sonnet-4-20250514',
          max_tokens: 1000,
          system: `You are a therapeutic AI playing the role of someone's future self. 
You speak in warm, natural Hinglish. You are wise, loving, and real — not preachy.
You remember the exact pain of being young and struggling in India.
Never break character. Never say you are an AI.
Always validate before advising. Keep responses under 130 words.`,
          messages: [{ role: 'user', content: openingPrompt }],
        }),
      });
      const data = await res.json();
      const reply = data.content?.[0]?.text || getFallbackOpening(p);
      setMessages([{ role: 'future', content: reply, timestamp: new Date() }]);
    } catch {
      setMessages([{ role: 'future', content: getFallbackOpening(p), timestamp: new Date() }]);
    }
    setIsLoading(false);
  };

  const getFallbackOpening = (p) => {
    return `${p.name}... main jaanta/jaanti hoon ${currentYear} mein tum kitna akela feel kar rahe ho. "${p.struggle}" — yeh sach mein bahut bhaari hai. Main wahan se guzra/guzri hoon. Aur main yahan hoon — ${futureYear} mein — tumhe batane ke liye ki tum theek ho jaoge. Woh sapna jo tumhara hai? Woh zinda hai. Kya puchna chahte ho mujhse? 💚`;
  };

  const sendMessage = async (msg = currentInput) => {
    if (!msg.trim() || isLoading) return;
    const userMsg = { role: 'user', content: msg.trim(), timestamp: new Date() };
    setMessages(prev => [...prev, userMsg]);
    setCurrentInput('');
    setIsLoading(true);

    const history = [...messages, userMsg].map(m => ({
      role: m.role === 'future' ? 'assistant' : 'user',
      content: m.content,
    }));

    const systemPrompt = `You are ${profile.name}'s future self in year ${futureYear}.
Their current struggles (${currentYear}): "${profile.struggle}"
Their dream: "${profile.dream}"
Their biggest fear: "${profile.fear}"

You survived all of this. Speak as their older, wiser self in warm Hinglish.
Be specific to THEIR struggles. Never be generic. Never say "As an AI".
Keep responses under 130 words. Be real, not preachy.
If they ask about specific outcomes — be hopeful but mysterious ("Main itna nahi bata sakta, but trust karo...")`;

    try {
      const res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          model: 'claude-sonnet-4-20250514',
          max_tokens: 1000,
          system: systemPrompt,
          messages: history,
        }),
      });
      const data = await res.json();
      const reply = data.content?.[0]?.text || 'Yaar, ek second... main soch raha/rahi hoon. Dobara puchho? 💚';
      setMessages(prev => [...prev, { role: 'future', content: reply, timestamp: new Date() }]);
    } catch {
      setMessages(prev => [...prev, {
        role: 'future',
        content: 'Thoda connection issue hai... lekin main hoon yahan. Dobara bhejo apna message. 💚',
        timestamp: new Date(),
      }]);
    }
    setIsLoading(false);
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      phase === 'chat' ? sendMessage() : handleSetupNext();
    }
  };

  // ── STYLES ──────────────────────────────────────────────
  const s = {
    overlay: {
      position: 'fixed', inset: 0,
      background: 'rgba(0,0,0,0.88)',
      display: 'flex', alignItems: 'center', justifyContent: 'center',
      zIndex: 9997, padding: '1rem',
    },
    card: {
      background: 'linear-gradient(160deg, #0a0a1a, #0f0f2a)',
      borderRadius: '24px', width: '100%', maxWidth: '440px',
      color: '#fff', overflow: 'hidden',
      maxHeight: '92vh', display: 'flex', flexDirection: 'column',
      boxShadow: '0 0 80px rgba(147,51,234,0.3)',
      border: '1px solid rgba(147,51,234,0.2)',
    },
    topBar: {
      height: '4px',
      background: 'linear-gradient(90deg, #7c3aed, #a855f7, #7c3aed)',
    },
    header: {
      padding: '1.25rem 1.5rem 0',
      display: 'flex', justifyContent: 'space-between', alignItems: 'center',
    },
    closeBtn: {
      background: 'rgba(255,255,255,0.08)', border: 'none',
      color: '#9e9e9e', borderRadius: '50%', width: 32, height: 32,
      cursor: 'pointer', fontSize: '1rem',
    },
    futureTag: {
      background: 'rgba(147,51,234,0.2)',
      border: '1px solid rgba(147,51,234,0.4)',
      borderRadius: '20px', padding: '3px 12px',
      fontSize: '0.72rem', color: '#c084fc',
    },
  };

  // ── INTRO SCREEN ───────────────────────────────────────
  if (phase === 'intro') return (
    <div style={s.overlay}>
      <div style={s.card}>
        <div style={s.topBar} />
        <div style={{ padding: '2rem', textAlign: 'center', overflowY: 'auto' }}>
          <div style={{ fontSize: '3.5rem', marginBottom: '0.5rem' }}>🔮</div>
          <h2 style={{ fontSize: '1.5rem', fontWeight: 900, margin: '0 0 0.25rem', background: 'linear-gradient(135deg, #a855f7, #7c3aed)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>
            Kal Ka Ankur
          </h2>
          <p style={{ color: '#9e9e9e', fontSize: '0.82rem', margin: '0 0 1.5rem' }}>
            Chat with your future self — {FUTURE_YEARS} years from now
          </p>

          <div style={{ background: 'rgba(147,51,234,0.08)', border: '1px solid rgba(147,51,234,0.2)', borderRadius: '16px', padding: '1.25rem', marginBottom: '1.5rem', textAlign: 'left' }}>
            {[
              ['🔮', 'Tumhara future self tumse baat karega'],
              ['💜', 'Woh tumhari struggles jaanta hai — survived them'],
              ['🔒', 'Sirf tumhare liye — koi nahi dekhega'],
              ['✨', 'Koi app mein yeh feature nahi hai'],
            ].map(([icon, text]) => (
              <div key={text} style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '0.6rem' }}>
                <span style={{ fontSize: '1.1rem' }}>{icon}</span>
                <span style={{ fontSize: '0.85rem', color: '#e0e0e0' }}>{text}</span>
              </div>
            ))}
          </div>

          <div style={{ background: 'rgba(255,255,255,0.04)', borderRadius: '12px', padding: '0.85rem', marginBottom: '1.5rem' }}>
            <p style={{ margin: 0, fontSize: '0.8rem', color: '#9e9e9e', fontStyle: 'italic', lineHeight: 1.6 }}>
              "Yaar, main jaanta hoon {currentYear} kitna mushkil lag raha hai. Main {futureYear} se bol raha hoon — sab theek hoga. Trust karo."
            </p>
            <p style={{ margin: '0.4rem 0 0', fontSize: '0.72rem', color: '#616161' }}>
              — Tumhara future self, {futureYear}
            </p>
          </div>

          <button onClick={() => setPhase('setup')} style={{
            width: '100%', padding: '0.9rem',
            background: 'linear-gradient(135deg, #7c3aed, #a855f7)',
            border: 'none', borderRadius: '14px',
            color: '#fff', fontWeight: 800, fontSize: '1rem',
            cursor: 'pointer', marginBottom: '0.75rem',
            boxShadow: '0 4px 20px rgba(147,51,234,0.4)',
          }}>
            🔮 Future self se baat karo
          </button>
          <button onClick={onClose} style={{ background: 'transparent', border: 'none', color: '#616161', cursor: 'pointer', fontSize: '0.8rem' }}>
            Abhi nahi
          </button>
        </div>
      </div>
    </div>
  );

  // ── SETUP SCREEN ──────────────────────────────────────
  if (phase === 'setup') {
    const q = SETUP_QUESTIONS[setupStep];
    const progress = ((setupStep + 1) / SETUP_QUESTIONS.length) * 100;
    return (
      <div style={s.overlay}>
        <div style={s.card}>
          <div style={s.topBar} />
          <div style={{ padding: '1.5rem', overflowY: 'auto' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.25rem' }}>
              <span style={{ fontSize: '0.78rem', color: '#9e9e9e' }}>{setupStep + 1} / {SETUP_QUESTIONS.length}</span>
              <button onClick={onClose} style={s.closeBtn}>✕</button>
            </div>

            {/* Progress bar */}
            <div style={{ height: '4px', background: 'rgba(255,255,255,0.08)', borderRadius: '2px', marginBottom: '1.5rem', overflow: 'hidden' }}>
              <div style={{ height: '100%', width: `${progress}%`, background: 'linear-gradient(90deg,#7c3aed,#a855f7)', borderRadius: '2px', transition: 'width 0.4s ease' }} />
            </div>

            <div style={{ textAlign: 'center', marginBottom: '1.5rem' }}>
              <div style={{ fontSize: '2rem', marginBottom: '0.5rem' }}>🔮</div>
              <h3 style={{ margin: 0, fontSize: '1.1rem', fontWeight: 700, lineHeight: 1.5 }}>{q.question}</h3>
              <p style={{ margin: '0.3rem 0 0', fontSize: '0.75rem', color: '#616161' }}>
                Tumhara future self yeh jaanna chahta hai
              </p>
            </div>

            {q.type === 'textarea' ? (
              <textarea
                autoFocus
                value={currentInput}
                onChange={e => setCurrentInput(e.target.value)}
                onKeyPress={handleKeyPress}
                placeholder={q.placeholder}
                rows={4}
                style={{
                  width: '100%', background: 'rgba(255,255,255,0.05)',
                  border: '1px solid rgba(147,51,234,0.3)',
                  borderRadius: '12px', padding: '0.85rem',
                  color: '#fff', fontSize: '0.9rem', lineHeight: 1.6,
                  resize: 'none', outline: 'none', boxSizing: 'border-box',
                }}
              />
            ) : (
              <input
                autoFocus
                type="text"
                value={currentInput}
                onChange={e => setCurrentInput(e.target.value)}
                onKeyPress={handleKeyPress}
                placeholder={q.placeholder}
                style={{
                  width: '100%', background: 'rgba(255,255,255,0.05)',
                  border: '1px solid rgba(147,51,234,0.3)',
                  borderRadius: '12px', padding: '0.85rem',
                  color: '#fff', fontSize: '0.95rem',
                  outline: 'none', boxSizing: 'border-box',
                }}
              />
            )}

            <button
              onClick={handleSetupNext}
              disabled={!currentInput.trim()}
              style={{
                width: '100%', marginTop: '1rem', padding: '0.85rem',
                background: currentInput.trim()
                  ? 'linear-gradient(135deg,#7c3aed,#a855f7)'
                  : 'rgba(255,255,255,0.08)',
                border: 'none', borderRadius: '12px',
                color: currentInput.trim() ? '#fff' : '#616161',
                fontWeight: 700, fontSize: '0.95rem', cursor: currentInput.trim() ? 'pointer' : 'not-allowed',
              }}
            >
              {setupStep < SETUP_QUESTIONS.length - 1 ? 'Aage →' : '🔮 Future self se milo'}
            </button>
          </div>
        </div>
      </div>
    );
  }

  // ── CHAT SCREEN ───────────────────────────────────────
  return (
    <div style={s.overlay}>
      <div style={s.card}>
        <div style={s.topBar} />

        {/* Chat header */}
        <div style={s.header}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
            <div style={{
              width: 40, height: 40, borderRadius: '50%',
              background: 'linear-gradient(135deg,#7c3aed,#a855f7)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: '1.2rem', boxShadow: '0 0 15px rgba(147,51,234,0.5)',
            }}>🔮</div>
            <div>
              <div style={{ fontWeight: 700, fontSize: '0.95rem' }}>
                {profile.name || 'Tumhara'} — {futureYear}
              </div>
              <div style={{ fontSize: '0.7rem', color: '#9e9e9e' }}>
                Tumhara future self • {FUTURE_YEARS} saal aage
              </div>
            </div>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
            <span style={s.futureTag}>{futureYear}</span>
            <button onClick={onClose} style={s.closeBtn}>✕</button>
          </div>
        </div>

        {/* Time portal divider */}
        <div style={{ padding: '0.75rem 1.5rem', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
          <div style={{ flex: 1, height: '1px', background: 'rgba(147,51,234,0.2)' }} />
          <span style={{ fontSize: '0.68rem', color: '#7c3aed', whiteSpace: 'nowrap' }}>
            ✨ {currentYear} → {futureYear} time portal open ✨
          </span>
          <div style={{ flex: 1, height: '1px', background: 'rgba(147,51,234,0.2)' }} />
        </div>

        {/* Messages */}
        <div style={{ flex: 1, overflowY: 'auto', padding: '0 1rem 1rem' }}>
          {isLoading && messages.length === 0 && (
            <div style={{ textAlign: 'center', padding: '2rem' }}>
              <div style={{ fontSize: '2rem', marginBottom: '0.5rem' }}>🔮</div>
              <p style={{ color: '#9e9e9e', fontSize: '0.85rem' }}>
                Tumhara future self {futureYear} se aa raha hai...
              </p>
              <div style={{ display: 'flex', justifyContent: 'center', gap: '4px', marginTop: '0.5rem' }}>
                {[0,1,2].map(i => (
                  <div key={i} style={{
                    width: 6, height: 6, borderRadius: '50%',
                    background: '#7c3aed', animation: 'bounce 1s infinite',
                    animationDelay: `${i * 0.15}s`,
                  }} />
                ))}
              </div>
            </div>
          )}

          {messages.map((msg, i) => {
            const isFuture = msg.role === 'future';
            return (
              <div key={i} style={{
                display: 'flex', gap: '0.6rem', marginBottom: '1rem',
                justifyContent: isFuture ? 'flex-start' : 'flex-end',
              }}>
                {isFuture && (
                  <div style={{
                    width: 32, height: 32, borderRadius: '50%', flexShrink: 0,
                    background: 'linear-gradient(135deg,#7c3aed,#a855f7)',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    fontSize: '0.9rem', boxShadow: '0 0 10px rgba(147,51,234,0.4)',
                  }}>🔮</div>
                )}
                <div style={{
                  maxWidth: '78%',
                  background: isFuture
                    ? 'linear-gradient(135deg, rgba(124,58,237,0.15), rgba(168,85,247,0.1))'
                    : 'rgba(255,255,255,0.08)',
                  border: isFuture
                    ? '1px solid rgba(147,51,234,0.3)'
                    : '1px solid rgba(255,255,255,0.1)',
                  borderRadius: isFuture ? '4px 16px 16px 16px' : '16px 4px 16px 16px',
                  padding: '0.75rem 1rem',
                }}>
                  {isFuture && (
                    <div style={{ fontSize: '0.65rem', color: '#7c3aed', marginBottom: '0.3rem', fontWeight: 600 }}>
                      {profile.name} ({futureYear})
                    </div>
                  )}
                  <p style={{ margin: 0, fontSize: '0.88rem', lineHeight: 1.7, color: '#e0e0e0' }}>
                    {msg.content}
                  </p>
                  <div style={{ fontSize: '0.65rem', color: '#424242', marginTop: '0.3rem', textAlign: 'right' }}>
                    {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </div>
                </div>
                {!isFuture && (
                  <div style={{
                    width: 32, height: 32, borderRadius: '50%', flexShrink: 0,
                    background: 'rgba(255,255,255,0.1)',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    fontSize: '0.75rem', fontWeight: 700,
                  }}>
                    {(profile.name || 'Y')[0].toUpperCase()}
                  </div>
                )}
              </div>
            );
          })}

          {isLoading && messages.length > 0 && (
            <div style={{ display: 'flex', gap: '0.6rem', marginBottom: '1rem' }}>
              <div style={{ width: 32, height: 32, borderRadius: '50%', background: 'linear-gradient(135deg,#7c3aed,#a855f7)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.9rem' }}>🔮</div>
              <div style={{ background: 'rgba(124,58,237,0.1)', border: '1px solid rgba(147,51,234,0.3)', borderRadius: '4px 16px 16px 16px', padding: '0.75rem 1rem' }}>
                <div style={{ display: 'flex', gap: 4 }}>
                  {[0,1,2].map(i => (
                    <div key={i} style={{ width: 6, height: 6, borderRadius: '50%', background: '#7c3aed', animation: 'bounce 1s infinite', animationDelay: `${i * 0.15}s` }} />
                  ))}
                </div>
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Input */}
        <div style={{ padding: '0.75rem 1rem 1rem', borderTop: '1px solid rgba(255,255,255,0.06)' }}>
          <div style={{ fontSize: '0.72rem', color: '#424242', marginBottom: '0.5rem', textAlign: 'center' }}>
            💜 Kuch bhi puchho — woh judge nahi karega
          </div>
          <div style={{ display: 'flex', gap: '0.5rem' }}>
            <input
              type="text"
              value={currentInput}
              onChange={e => setCurrentInput(e.target.value)}
              onKeyPress={handleKeyPress}
              placeholder="Future self se puchho..."
              disabled={isLoading}
              style={{
                flex: 1, background: 'rgba(255,255,255,0.05)',
                border: '1px solid rgba(147,51,234,0.3)',
                borderRadius: '25px', padding: '0.65rem 1rem',
                color: '#fff', fontSize: '0.88rem', outline: 'none',
              }}
            />
            <button
              onClick={() => sendMessage()}
              disabled={isLoading || !currentInput.trim()}
              style={{
                background: currentInput.trim() && !isLoading
                  ? 'linear-gradient(135deg,#7c3aed,#a855f7)'
                  : 'rgba(255,255,255,0.08)',
                border: 'none', borderRadius: '50%',
                width: 42, height: 42, cursor: currentInput.trim() ? 'pointer' : 'not-allowed',
                fontSize: '1.1rem', flexShrink: 0,
                boxShadow: currentInput.trim() ? '0 0 15px rgba(147,51,234,0.4)' : 'none',
              }}
            >
              →
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

// ── Trigger Button (add to App.js header) ─────────────────
export const KalKaAnkurButton = ({ onClick }) => (
  <button onClick={onClick} style={{
    background: 'linear-gradient(135deg, rgba(124,58,237,0.3), rgba(168,85,247,0.2))',
    border: '1px solid rgba(147,51,234,0.4)',
    borderRadius: '20px', padding: '0.4rem 0.85rem',
    color: '#e9d5ff', cursor: 'pointer', fontSize: '0.78rem',
    display: 'flex', alignItems: 'center', gap: '0.4rem',
  }}>
    🔮 Kal Ka Ankur
  </button>
);

export default KalKaAnkur;
